import { DataModule } from '../../types';
import { fetchOpenMeteo } from '../apis/open-meteo';

export const noiseModule: DataModule = {
  id: 'noise',
  name: 'Noise Level',
  weight: 0.08,
  icon: 'volume-2',
  enabled: true,
  async fetch(lat, lon) {
    const data = await fetchOpenMeteo('forecast', {
      latitude: lat.toString(),
      longitude: lon.toString(),
      current: 'is_day',
      timezone: 'auto'
    });

    const localTime = new Date(data.current.time);
    const hour = localTime.getHours();

    return {
      lat,
      lon,
      is_day: data.current.is_day,
      hour
    };
  },
  normalize(data: any) {
    const { lat, hour } = data;

    // Daytime is 6 to 22
    const isDaytime = hour >= 6 && hour < 22;

    // Heuristic: abs(lat) < 35 = tropical urban = noisier
    const isTropicalUrban = Math.abs(lat) < 35;

    // Base noise level (0 = very noisy, 100 = quiet)
    let score = 100;

    if (isTropicalUrban) {
      // Tropical urban is generally noisier
      score -= 40;
    } else {
      // Other areas are less noisy
      score -= 10;
    }

    if (isDaytime) {
      // Daytime is noisier
      score -= 30;
    }

    return Math.max(0, Math.min(100, score));
  }
};

