import { describe, it, expect } from 'vitest';
import { noiseModule } from '../modules/noise';

describe('noiseModule', () => {
  it('should return a score between 0 and 100', () => {
    const data = {
      lat: 40.7128, // NYC
      lon: -74.0060,
      is_day: 1,
    };
    const score = noiseModule.normalize(data);
    expect(score).toBeGreaterThanOrEqual(0);
    expect(score).toBeLessThanOrEqual(100);
  });

  it('should be noisier (lower score) during the day in urban areas', () => {
    const dayData = { lat: 34.0522, lon: -118.2437, is_day: 1 }; // LA, day
    const nightData = { lat: 34.0522, lon: -118.2437, is_day: 0 }; // LA, night

    const dayScore = noiseModule.normalize(dayData);
    const nightScore = noiseModule.normalize(nightData);

    expect(dayScore).toBeLessThan(nightScore);
  });

  it('should be noisier (lower score) in tropical/urban areas compared to high latitudes', () => {
    const tropicalData = { lat: 1.3521, lon: 103.8198, is_day: 1 }; // Singapore
    const ruralData = { lat: 60.1699, lon: 24.9384, is_day: 1 }; // Helsinki

    const tropicalScore = noiseModule.normalize(tropicalData);
    const ruralScore = noiseModule.normalize(ruralData);

    expect(tropicalScore).toBeLessThan(ruralScore);
  });

  it('should handle extreme latitudes gracefully', () => {
    const data = { lat: 90, lon: 0, is_day: 1 }; // North Pole
    const score = noiseModule.normalize(data);
    expect(score).toBeGreaterThanOrEqual(0);
    expect(score).toBeLessThanOrEqual(100);
  });
});

